import { pollAgentSessionEvents } from "../agentSessionChannel.js";
import { openChromelessWindow } from "../browser.js";
import { recordFocus } from "../frontmostApp.js";
export function openStudio({ serviceUrl, apiKey, sessionId, }) {
    const restoreFocus = recordFocus();
    const url = `${serviceUrl}/studio?session=${encodeURIComponent(sessionId)}`;
    openChromelessWindow(url);
    const abortController = new AbortController();
    pollAgentSessionEvents({
        serviceUrl,
        apiKey,
        sessionId,
        abortSignal: abortController.signal,
        onEvent: (event) => {
            if (event.type === "studio:return-to-agent") {
                restoreFocus();
            }
        },
        onError: (err) => {
            console.error(`studio agent-event poll: ${err.message}`);
        },
    }).catch((err) => {
        console.error(`studio agent-event poll terminated: ${err.message}`);
    });
    return {
        sessionId,
        abort: () => abortController.abort(),
    };
}
